const detail='\n<div>\n    <template v-for="kind in kinds">\n        <template v-if="kind.category == category">\n            <template v-for="work in kind.works">\n                <template v-if="work.name == name">\n                    <div class="container d-none d-sm-block">\n                        <div class="work-detail-title">\n                            <div class="row">\n                                <div class="col-lg-12">\n                                    <div class="title-bg">{{ work.title_en }}</div>\n                                </div>\n                                <div class="col-lg-10 offset-lg-2">\n                                    <div class="title-box">\n                                        <div class="title-name">{{ work.title }}</div>\n                                        <div class="title-content">{{ work.description }}</div>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                \n                    <div class="container">\n                        <div class="work-detail">\n                            <div class="row">\n                                <div class="col-lg-8 col-sm-12">\n                                    <div class="work-detail-acticle">\n                                        <div class="post_wrap">\n                                            <div v-html="post"></div>\n                                        </div>\n                                    </div>\n                                </div>\n                                <div class="col-lg-4 col-sm-12 order-first order-sm-0">\n                                    <div class="work-detail-info d-flex flex-column">    \n                                        <div class="info-cover order-0 order-sm-0">\n                                            \x3c!--<img v-bind:src="work.image" />--\x3e\n\n                                            <picture>\n                                                <source v-bind:srcset="work.webp" type="image/webp">\n                                                <img v-bind:src="work.image" v-bind:alt="work.title" />\n                                            </picture>\n                                        </div>\n                                        <div class="info-year order-1 order-sm-1">{{ work.year }}</div>\n                                        <div class="info-title order-2 order-sm-2">{{work.title}}</div>\n                                        <div class="info-link order-3 order-sm-3">\n                                            <a v-if="work.link" class="link-icon icon-website" target="_blank" v-bind:href="work.link">{{work.link}}</a>\n                                            <a v-if="work.github" class="link-icon icon-github" target="_blank" v-bind:href="work.github">{{work.github}}</a>\n                                        </div>\n                                        <hr class="order-5 order-sm-4" />\n                                        <div class="info-sub-title order-6 order-sm-5">負責部分</div>\n                                        <div class="info-content order-7 order-sm-6">\n                                            <template v-for="info_content in work.info_contents">\n                                                {{info_content}}<br>\n                                            </template>\n                                        </div>\n                                        <div class="info-sub-title d-none d-sm-block order-sm-7">工具</div>\n                                        <div class="tagbox order-4 order-sm-8">\n                                            <div class="tag-item" v-for="tag in work.tags">{{tag}}</div>\n                                        </div>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </template>\n            </template>\n        </template>\n    </template>\n</div>\n',Detail={props:["category","name"],template:detail,data:()=>({kinds:[],post:"",isMac:!1}),created(){this.fetchData(),this.fetchDataHTML(),this.isMac=navigator.platform.toUpperCase().indexOf("MAC")>=0},mounted:function(){$("#js-goback-btn").addClass("show")},updated(){let t=$(".dev-outter-wrap");!this.isMac&&t.length>0&&t.addClass("hide-scroll")},methods:{fetchData(){fetch("dist/assets/data/works.json").then((t=>t.json())).then((t=>{this.kinds=t}))},fetchDataHTML(){fetch(`dist/assets/data/contents/${this.$route.params.name}.html`).then((t=>t.text())).then((t=>this.post=t)).then((function(){$(".tab-nav").on("click",(function(){let t=$(this).parent(".tab-nav-wrap").attr("data-panel"),i=$(this).attr("data-tabs");$(this).siblings(".active").removeClass("active"),$(this).addClass("active");let n=$(".tab-content-wrap").filter(`[data-panel="${t}"]`);n.find(".active").removeClass("active"),n.find(`[data-tabs="${i}"]`).addClass("active")}))}))},checkRoute:function(){let t=!0;for(let i=0;i<this.kinds.length;i++)if(this.kinds[i].category==this.$route.params.category)for(let n=0;n<this.kinds[i].works.length;n++)this.kinds[i].works[n].name==this.$route.params.name&&(t=!1);t&&this.$router.push("/404-not-found")}},watch:{$route:function(t,i){this.checkRoute()}}};export default Detail;